import Box from '@mui/material/Box'
import SelfiePicker, {SelfieType} from '../SelfiePicker/selfie-picker';
import Button from '@mui/material/Button';
import { useState } from "react";
import { ColorPicker, ColorPickerButton } from '../Shared/Layout/ColorPicker/colorpicker';
import useMediaQuery from '@mui/material/useMediaQuery';
import { createTheme } from '@mui/material/styles';

const theme = createTheme({
    palette: {
      primary: {
        main: '#0077c2',
      },
    },
  });

const images = [
    "Lela",
    "EmoLela",
    "AnimuLela",
    "ShortHairLela",
    "BraidedLela",
    "VulcanLela",
    "StraightHairLela",
    "BracesLela",
    "LelaOfGreenGables",
    "WhatTheCat",
    "RinguLela",
    "DudeLela",
    "FunkyLela",
    "Rockin'Lela",
    "FreshlyShoweredLela",
    "PoofyLela",
    "ChildLela"
];

function Home() {


    const [imageString, setImageString] = useState<string>("Lela");
    const [displayedImageName, setDisplayedImageName] = useState<string>("Lela");
    const [drawerOpen, setDrawerOpen] = useState<boolean>(false)
    const [currentIcon, setCurrentIcon] = useState("selfie");

     //Make the colorpicker btn responsive
     const isMobile: boolean = useMediaQuery(theme.breakpoints.down('sm'));

    const SelfieType: SelfieType = {
        randomImage: imageString
    }

    function randomizeImg() {
        const randomImage = images[Math.floor(images.length * Math.random())];
        setImageString(randomImage);
        setDisplayedImageName(randomImage);
    }

    //Regex expression to split the img-namestring at the uppercased letters
    const formattedImageName = imageString.replace(/([A-Z])/g, ' $1');

    const handleColorPickerOpen = () => {
        setDrawerOpen(true);
    };

    const buttons = [
      { className: "hair", label: "Hair" },
      { className: "shirt", label: "Shirt" },
      { className: "lips", label: "Lipstick" },
      { className: "eyelids", label: "Eyeshadow" },
      { className: "eyeglasses", label: "Glasses" },
      { className: "hearingaid-inner", label: "Hearing Aids" }
    ];

    // Check whether the current SVG contains the "beard" class name and add the "Change Beard Color" button if necessary
  if (currentIcon === "DudeLela") {
    const svgElement = images.find(images => icon.name === currentIcon)?.component?.props.children;
    if (svgElement && svgElement.props.className.includes("beard")) {
      buttons.push({ className: "beard", label: "Beard" });
    }
  }


    return (
        <>
            <Box
                display="flex"
                justifyContent="center"
                height="400px"
            >
                <SelfiePicker {...SelfieType} />
            </Box>
            <Box
            textAlign="center"
            marginTop="120px"
            marginBottom="10px"
            marginLeft="40px"
            marginRight="40px"
            style={{
                backgroundColor: 'rgba(0, 0, 0, 0.5)',
                borderRadius: '15px',
                padding: '2px',
    
                color: '#fff'
              }}
            >
             <h3>{formattedImageName}</h3>
      </Box>
      <Box display="flex" justifyContent="center">
        <Button variant="contained" onClick={() => randomizeImg()}>
          Change Me
        </Button>
        <ColorPickerButton onClick={() => setDrawerOpen(true)} isMobile={isMobile} />
      </Box>
      <ColorPicker drawerOpen={drawerOpen} setDrawerOpen={setDrawerOpen} activeIcon={activeIcon}/>
    </>
  )
}

export default Home;
